int countTargetSumExpressions(vector<int>& numbers, int targetSum) {
    long long totalSum = accumulate(numbers.begin(), numbers.end(), 0LL);

    // Validation:
    // 1. Total sum must be sufficient to reach target
    // 2. (TotalSum + Target) must be even for P to be an integer
    if (totalSum < abs(targetSum) || (totalSum + targetSum) % 2 != 0) {
        return 0;
    }

    int subsetTarget = (totalSum + targetSum) / 2;

    // DP Table: dp[i] = number of ways to get sum 'i'
    vector<int> dp(subsetTarget + 1, 0);
    dp[0] = 1; // Base Case

    for (int num : numbers) {
        // Iterate backwards to avoid using the same number twice in one step
        for (int i = subsetTarget; i >= num; i--) {
            dp[i] += dp[i - num];
        }
    }

    return dp[subsetTarget];
}

