def countTargetSumExpressions(numbers: list[int], targetSum: int) -> int:
    total_sum = sum(numbers)

    # Validation
    if total_sum < abs(targetSum) or (total_sum + targetSum) % 2 != 0:
        return 0

    subset_target = (total_sum + targetSum) // 2

    # Initialize DP table
    dp = [0] * (subset_target + 1)
    dp[0] = 1

    for num in numbers:
        for i in range(subset_target, num - 1, -1):
            dp[i] += dp[i - num]

    return dp[subset_target]

