int countTargetSumExpressions(int* numbers, int n, int targetSum) {
    long long totalSum = 0;
    for (int i = 0; i < n; i++) totalSum += numbers[i];

    // Validation
    if (totalSum < abs(targetSum) || (totalSum + targetSum) % 2 != 0) {
        return 0;
    }

    int subsetTarget = (totalSum + targetSum) / 2;

    // Use calloc to initialize DP array with 0
    int* dp = (int*)calloc(subsetTarget + 1, sizeof(int));
    if (dp == NULL) return 0;

    dp[0] = 1; // Base Case

    for (int i = 0; i < n; i++) {
        for (int j = subsetTarget; j >= numbers[i]; j--) {
            dp[j] += dp[j - numbers[i]];
        }
    }

    int result = dp[subsetTarget];
    free(dp);
    return result;
}

