function countTargetSumExpressions(numbers, targetSum) {
    const totalSum = numbers.reduce((a, b) => a + b, 0);

    // Validation
    if (totalSum < Math.abs(targetSum) || (totalSum + targetSum) % 2 !== 0) {
        return 0;
    }

    const subsetTarget = (totalSum + targetSum) / 2;
    const dp = new Array(subsetTarget + 1).fill(0);
    dp[0] = 1;

    for (const num of numbers) {
        for (let i = subsetTarget; i >= num; i--) {
            dp[i] += dp[i - num];
        }
    }

    return dp[subsetTarget];
}
